            + FfiConverterOptionalString.INSTANCE.AllocationSize(value.PosthogApiKey)
            + FfiConverterOptionalString.INSTANCE.AllocationSize(value.RageshakeSubmitUrl)
            + FfiConverterOptionalString.INSTANCE.AllocationSize(value.SentryDsn)
            + FfiConverterOptionalString.INSTANCE.AllocationSize(value.SentryEnvironment);
    }

    public override void Write(VirtualElementCallWidgetProperties value, BigEndianStream stream) {
            FfiConverterString.INSTANCE.Write(value.ElementCallUrl, stream);
            FfiConverterString.INSTANCE.Write(value.WidgetId, stream);
            FfiConverterOptionalString.INSTANCE.Write(value.ParentUrl, stream);
            FfiConverterOptionalDouble.INSTANCE.Write(value.FontScale, stream);
            FfiConverterOptionalString.INSTANCE.Write(value.Font, stream);
            FfiConverterTypeEncryptionSystem.INSTANCE.Write(value.Encryption, stream);
            FfiConverterOptionalString.INSTANCE.Write(value.PosthogUserId, stream);
            FfiConverterOptionalString.INSTANCE.Write(value.PosthogApiHost, stream);
            FfiConverterOptionalString.INSTANCE.Write(value.PosthogApiKey, stream);
            FfiConverterOptionalString.INSTANCE.Write(value.RageshakeSubmitUrl, stream);
            FfiConverterOptionalString.INSTANCE.Write(value.SentryDsn, stream);
            FfiConverterOptionalString.INSTANCE.Write(value.SentryEnvironment, stream);
    }
}





/// <summary>
/// Settings for end-to-end encryption features.
/// </summary>
public enum BackupDownloadStrategy: int {
    /// <summary>
    /// Automatically download all room keys from the backup when the backup
    /// recovery key has been received. The backup recovery key can be received
    /// in two ways:
    ///
    /// 1. Received as a `m.secret.send` to-device event, after a successful
    /// interactive verification.
    /// 2. Imported from secret storage (4S) using the
    /// [`SecretStore::import_secrets()`] method.
    ///
    /// [`SecretStore::import_secrets()`]: crate::encryption::secret_storage::SecretStore::import_secrets
    /// </summary>
    OneShot,
    /// <summary>
    /// Attempt to download a single room key if an event fails to be decrypted.
    /// </summary>
    AfterDecryptionFailure,
    /// <summary>
    /// Don't download any room keys automatically. The user can manually
    /// download room keys using the [`Backups::download_room_key()`] methods.
    ///
    /// This is the default option.
    /// </summary>
    Manual
}

class FfiConverterTypeBackupDownloadStrategy: FfiConverterRustBuffer<BackupDownloadStrategy> {
    public static FfiConverterTypeBackupDownloadStrategy INSTANCE = new FfiConverterTypeBackupDownloadStrategy();

    public override BackupDownloadStrategy Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1: return BackupDownloadStrategy.OneShot;
            case 2: return BackupDownloadStrategy.AfterDecryptionFailure;
            case 3: return BackupDownloadStrategy.Manual;
            default: throw new publicException(String.Format("invalid enum value '{0}' in FfiConverterTypeBackupDownloadStrategy.Read()", value));
        }
    }

    public override int AllocationSize(BackupDownloadStrategy value) {
        return 4;
    }

    public override void Write(BackupDownloadStrategy value, BigEndianStream stream) {
        switch (value) {
            case BackupDownloadStrategy.OneShot: stream.WriteInt(1); break;
            case BackupDownloadStrategy.AfterDecryptionFailure: stream.WriteInt(2); break;
            case BackupDownloadStrategy.Manual: stream.WriteInt(3); break;
            default: throw new publicException(String.Format("invalid enum value '{0}' in FfiConverterTypeBackupDownloadStrategy.Write()", value));
        }
    }
}







/// <summary>
