/// <summary>
/// The error type for failures while trying to log in a new device using a QR
/// code.
/// </summary>
public class QrCodeLoginException: UniffiException {
    QrCodeLoginException(string message): base(message) {}

    // Each variant is a nested class
    // Flat enums carries a string error message, so no special implementation is necessary.
    
    /// <summary>
    /// An error happened while we were communicating with the OAuth 2.0
    /// authorization server.
    /// </summary>
    public class OAuth: QrCodeLoginException {
        public OAuth(string message): base(message) {}
    }
    
    /// <summary>
    /// The other device has signaled to us that the login has failed.
    /// </summary>
    public class LoginFailure: QrCodeLoginException {
        public LoginFailure(string message): base(message) {}
    }
    
    /// <summary>
    /// An unexpected message was received from the other device.
    /// </summary>
    public class UnexpectedMessage: QrCodeLoginException {
        public UnexpectedMessage(string message): base(message) {}
    }
    
    /// <summary>
    /// An error happened while exchanging messages with the other device.
    /// </summary>
    public class SecureChannel: QrCodeLoginException {
        public SecureChannel(string message): base(message) {}
    }
    
    /// <summary>
    /// The rendezvous session was not found and might have expired.
    /// </summary>
    public class NotFound: QrCodeLoginException {
        public NotFound(string message): base(message) {}
    }
    
    /// <summary>
    /// The cross-process refresh lock failed to be initialized.
    /// </summary>
    public class CrossProcessRefreshLock: QrCodeLoginException {
        public CrossProcessRefreshLock(string message): base(message) {}
    }
    
    /// <summary>
    /// An error happened while we were trying to discover our user and device
    /// ID, after we have acquired an access token from the OAuth 2.0
    /// authorization server.
    /// </summary>
    public class UserIdDiscovery: QrCodeLoginException {
        public UserIdDiscovery(string message): base(message) {}
    }
    
    /// <summary>
    /// We failed to set the session tokens after we figured out our device and
    /// user IDs.
    /// </summary>
    public class SessionTokens: QrCodeLoginException {
        public SessionTokens(string message): base(message) {}
    }
    
    /// <summary>
    /// The device keys failed to be uploaded after we successfully logged in.
    /// </summary>
    public class DeviceKeyUpload: QrCodeLoginException {
        public DeviceKeyUpload(string message): base(message) {}
    }
    
    /// <summary>
    /// The secrets bundle we received from the existing device failed to be
    /// imported.
    /// </summary>
    public class SecretImport: QrCodeLoginException {
        public SecretImport(string message): base(message) {}
    }
    
    /// <summary>
    /// The other party told us to use a different homeserver but we failed to
    /// reset the server URL.
    /// </summary>
    public class ServerReset: QrCodeLoginException {
        public ServerReset(string message): base(message) {}
    }
    
}

class FfiConverterTypeQRCodeLoginError : FfiConverterRustBuffer<QrCodeLoginException>, CallStatusErrorHandler<QrCodeLoginException> {
    public static FfiConverterTypeQRCodeLoginError INSTANCE = new FfiConverterTypeQRCodeLoginError();

    public override QrCodeLoginException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1: return new QrCodeLoginException.OAuth(FfiConverterString.INSTANCE.Read(stream));
            case 2: return new QrCodeLoginException.LoginFailure(FfiConverterString.INSTANCE.Read(stream));
            case 3: return new QrCodeLoginException.UnexpectedMessage(FfiConverterString.INSTANCE.Read(stream));
            case 4: return new QrCodeLoginException.SecureChannel(FfiConverterString.INSTANCE.Read(stream));
            case 5: return new QrCodeLoginException.NotFound(FfiConverterString.INSTANCE.Read(stream));
            case 6: return new QrCodeLoginException.CrossProcessRefreshLock(FfiConverterString.INSTANCE.Read(stream));
            case 7: return new QrCodeLoginException.UserIdDiscovery(FfiConverterString.INSTANCE.Read(stream));
            case 8: return new QrCodeLoginException.SessionTokens(FfiConverterString.INSTANCE.Read(stream));
            case 9: return new QrCodeLoginException.DeviceKeyUpload(FfiConverterString.INSTANCE.Read(stream));
            case 10: return new QrCodeLoginException.SecretImport(FfiConverterString.INSTANCE.Read(stream));
            case 11: return new QrCodeLoginException.ServerReset(FfiConverterString.INSTANCE.Read(stream));
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeQRCodeLoginError.Read()", value));
        }
    }

    public override int AllocationSize(QrCodeLoginException value) {
        return 4 + FfiConverterString.INSTANCE.AllocationSize(value.Message);
    }

    public override void Write(QrCodeLoginException value, BigEndianStream stream) {
        switch (value) {
            case QrCodeLoginException.OAuth:
                stream.WriteInt(1);
                break;
            case QrCodeLoginException.LoginFailure:
                stream.WriteInt(2);
                break;
            case QrCodeLoginException.UnexpectedMessage:
                stream.WriteInt(3);
                break;
            case QrCodeLoginException.SecureChannel:
                stream.WriteInt(4);
                break;
            case QrCodeLoginException.NotFound:
                stream.WriteInt(5);
                break;
            case QrCodeLoginException.CrossProcessRefreshLock:
                stream.WriteInt(6);
                break;
            case QrCodeLoginException.UserIdDiscovery:
                stream.WriteInt(7);
                break;
            case QrCodeLoginException.SessionTokens:
                stream.WriteInt(8);
                break;
            case QrCodeLoginException.DeviceKeyUpload:
                stream.WriteInt(9);
                break;
            case QrCodeLoginException.SecretImport:
                stream.WriteInt(10);
                break;
            case QrCodeLoginException.ServerReset:
                stream.WriteInt(11);
                break;
            default:
                throw new publicException(String.Format("invalid error value '{0}' in FfiConverterTypeQRCodeLoginError.Write()", value));
        }
    }
}





